const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

export function quote(input: QuoteInput): { premium: number } {
  if (input.items.length === 0) return { premium: PROCESSING_FEE };

  const item = input.items[0];
  let policyBase = BASE_PREMIUMS[item.type];
  if (input.customer.previousContracts === 0) {
    policyBase = policyBase * (1 + FIRST_INSURANCE_SURCHARGE);
  }
  const total = Math.ceil(Math.round(policyBase * 100) / 100 + PROCESSING_FEE);
  return { premium: total };
}
